import pytest

def test_submit_timesheet_per_day_hours_exceed_24_returns_422(auth_client):
    payload = {
        "week": <current_week_fixture>,
        "days": {
            "mon": 25, "tue": 8, "wed": 8, "thu": 8, "fri": 8,
            "sat": 0, "sun": 0
        }
    }
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code == 422
    body = resp.json()
    assert "mon" in str(body).lower() or "hours" in str(body).lower()
    status_resp = auth_client.get("/timesheets/current")
    assert status_resp.json()["state"] != "submitted"

