def test_submit_timesheet_boundary_max_daily_and_max_weekly(auth_client, webhook_listener):
    payload = {
        "week": <current_week_fixture>,
        "days": {
            "mon": 16, "tue": 16, "wed": 16, "thu": 16, "fri": 16,
            "sat": 0, "sun": 0
        }
    }
    assert sum(payload["days"].values()) == 80
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code == 200
    assert resp.json()["state"] == "submitted"
    event = webhook_listener.wait_for_event(timeout=5)
    assert event is not None

