def test_submit_timesheet_decision_table_both_constraints_violated(auth_client):
    payload = {
        "week": <current_week_fixture>,
        "days": {
            "mon": 25, "tue": 25, "wed": 25, "thu": 25, "fri": 25,
            "sat": 0, "sun": 0
        }
    }
    assert sum(payload["days"].values()) > 80
    assert any(v > 24 for v in payload["days"].values())
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code == 422
    status_resp = auth_client.get("/timesheets/current")
    assert status_resp.json()["state"] != "submitted"
